const MORPH_RISE_DURATION = 0.8
const FALL_DURATION = 0.6
const IMPACT_DURATION = 0.12
const BOUNCE_RISE_DURATION = 0.6

const STABLE_PARTICLE_DATA = Array.from({ length: 12 }, (_, i) => {
  const angle = (i / 12) * Math.PI * 2
  const dist = 40 + (((i * 7 + 3) % 11) / 11) * 40
  return {
    id: i,
    tx: Math.cos(angle) * dist,
    ty: Math.sin(angle) * dist - 8,
    dur: 0.3 + (((i * 3 + 5) % 8) / 8) * 0.2,
  }
})

const STABLE_BG_DOTS = Array.from({ length: 24 }, (_, i) => ({
  id: i,
  x: ((i * 37 + 13) % 100),
  y: ((i * 53 + 7) % 100),
  size: 1 + ((i * 11 + 3) % 10) / 10 * 1.5,
  dur: 3 + ((i * 7 + 2) % 10) / 10 * 4,
  delay: ((i * 13 + 1) % 10) / 10 * 3,
}))

function ChessSVG({ opacity = 1 }: { opacity?: number }) {
  return (
    <svg viewBox="0 0 1254 1254" width={ICON_SIZE} height={ICON_SIZE} style={{ opacity }}>
      <path
        d={CHESS_PATH_1}
        fill="black"
        transform="translate(0,0)"
      />
      <path
        d={CHESS_PATH_2}
        fill="#F4F4F5"
        transform="translate(595.503173828125,45.70947265625)"
        style={{ filter: "drop-shadow(0 0 8px rgba(255,255,255,0.3))" }}
      />
      <path
        d={CHESS_PATH_3}
        fill="none"
        stroke="#F4F4F5"
        strokeWidth="4"
        strokeLinecap="round"
        strokeLinejoin="round"
        transform="translate(595.503173828125,45.70947265625)"
        style={{ filter: "drop-shadow(0 0 4px rgba(255,255,255,0.2))" }}
      />
    </svg>
  )
}

function CarSVG({ opacity = 1 }: { opacity?: number }) {
  return (
    <svg viewBox="0 0 1774 887" width={ICON_SIZE * 1.4} height={ICON_SIZE * 0.7} style={{ opacity }}>
      <path
        d={CAR_PATH_1}
        fill="black"
      />
      <path
        d={CAR_PATH_2}
        fill="#F4F4F5"
        style={{ filter: "drop-shadow(0 0 8px rgba(255,255,255,0.3))" }}
      />
    </svg>
  )
}

function Shockwave() {
  return (
    <motion.div
      style={{
        position: "absolute",
        bottom: "22%",
        left: "50%",
        width: 120,
        height: 30,
        marginLeft: -60,
        borderRadius: "50%",
        border: "2px solid rgba(255,255,255,0.5)",
        pointerEvents: "none",
      }}
      initial={{ scale: 0.3, opacity: 1 }}
      animate={{ scale: 1.5, opacity: 0 }}
      transition={{ duration: 0.35, ease: "easeOut" }}
    />
  )
}

function GroundFlash() {
  return (
    <motion.div
      style={{
        position: "absolute",
        bottom: "20%",
        left: "50%",
        width: 140,
        height: 4,
        marginLeft: -70,
        borderRadius: 2,
        background: "radial-gradient(ellipse, rgba(255,255,255,0.8), transparent 70%)",
        pointerEvents: "none",
      }}
      initial={{ opacity: 1, scaleX: 0.5 }}
      animate={{ opacity: 0, scaleX: 1.4 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
    />
  )
}

function BurstParticles() {
  return (
    <>
      {STABLE_PARTICLE_DATA.map((p) => (
        <motion.div
          key={p.id}
          style={{
            position: "absolute",
            bottom: "22%",
            left: "50%",
            width: 3,
            height: 3,
            marginLeft: -1.5,
            borderRadius: "50%",
            background: "white",
            pointerEvents: "none",
          }}
          initial={{ x: 0, y: 0, opacity: 1, scale: 1 }}
          animate={{ x: p.tx, y: p.ty, opacity: 0, scale: 0 }}
          transition={{ duration: p.dur, ease: "easeOut" }}
        />
      ))}
    </>
  )
}

function Scanline() {
  return (
    <motion.div
      style={{
        position: "absolute",
        inset: 0,
        background: "linear-gradient(to bottom, transparent 0%, rgba(255,255,255,0.015) 50%, transparent 100%)",
        height: "100%",
        pointerEvents: "none",
      }}
      animate={{ y: ["-100%", "100%"] }}
      transition={{ duration: 5, repeat: Infinity, ease: "linear" }}
    />
  )
}

function BackgroundParticles() {
  return (
    <>
      {STABLE_BG_DOTS.map((d) => (
        <motion.div
          key={d.id}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: d.size,
            height: d.size,
            borderRadius: "50%",
            background: "rgba(255,255,255,0.15)",
            pointerEvents: "none",
          }}
          animate={{ opacity: [0.05, 0.3, 0.05], scale: [0.8, 1.1, 0.8] }}
          transition={{ duration: d.dur, delay: d.delay, repeat: Infinity, ease: "easeInOut" }}
        />
      ))}
    </>
  )
}

export default function PlayfulLoader({ progress = 0 }: { progress?: number }) {
  const [phase, setPhase] = useState<Phase>("falling")
  const [showImpact, setShowImpact] = useState(false)
  const [isChess, setIsChess] = useState(true)

  const advanceToChess = useCallback(() => {
    setIsChess(true)
    setPhase("falling")
  }, [])

  const advanceToCar = useCallback(() => {
    setIsChess(false)
    setPhase("falling")
  }, [])

  useEffect(() => {
    if (phase === "falling") {
      const t = setTimeout(() => setPhase("impact"), FALL_DURATION * 1000)
      return () => clearTimeout(t)
    }
    if (phase === "impact") {
      setShowImpact(true)
      const t = setTimeout(() => {
        setShowImpact(false)
        setPhase("rising")
      }, IMPACT_DURATION * 1000)
      return () => clearTimeout(t)
    }
    if (phase === "rising") {
      const t = setTimeout(() => setPhase("at_top"), MORPH_RISE_DURATION * 1000)
      return () => clearTimeout(t)
    }
    if (phase === "at_top") {
      const t = setTimeout(() => {
        if (isChess) {
          advanceToCar()
        } else {
          advanceToChess()
        }
      }, 300)
      return () => clearTimeout(t)
    }
  }, [phase, isChess, advanceToChess, advanceToCar])

  const getObjectTransform = () => {
    switch (phase) {
      case "falling":
        return { y: -200, rotate: 0, scale: 1, scaleX: 1, scaleY: 1 }
      case "impact":
        return { y: 0, rotate: 0, scale: 1, scaleX: 1.15, scaleY: 0.82 }
      case "rising":
        return { y: -180, rotate: 0, scale: 1, scaleX: 1, scaleY: 1 }
      case "at_top":
        return { y: -200, rotate: 0, scale: 1, scaleX: 1, scaleY: 1 }
      default:
        return { y: 0, rotate: 0, scale: 1, scaleX: 1, scaleY: 1 }
    }
  }

  const getTransition = () => {
    switch (phase) {
      case "falling":
        return { duration: FALL_DURATION, ease: [0.55, 0, 1, 0.45] as [number, number, number, number] }
      case "impact":
        return { duration: IMPACT_DURATION, ease: "easeOut" as const }
      case "rising":
        return { duration: MORPH_RISE_DURATION, ease: [0.34, 1.56, 0.64, 1] as [number, number, number, number] }
      case "at_top":
        return { duration: 0.3, ease: "easeInOut" as const }
      default:
        return { duration: 0.3, ease: "easeOut" as const }
    }
  }

  const showCurrent = phase === "falling" || phase === "impact"
  const showNext = phase === "rising" || phase === "at_top"

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "#05060B",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        zIndex: 9999,
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          background: "radial-gradient(ellipse at 50% 40%, rgba(255,255,255,0.025) 0%, transparent 55%)",
          pointerEvents: "none",
        }}
      />
      <div
        style={{
          position: "absolute",
          inset: 0,
          background: "radial-gradient(ellipse at 50% 80%, rgba(80,100,255,0.015) 0%, transparent 50%)",
          pointerEvents: "none",
        }}
      />

      <Scanline />
      <BackgroundParticles />

      <div style={{ position: "relative", width: ICON_SIZE * 1.4, height: ICON_SIZE * 1.4 }}>
        <motion.div
          animate={getObjectTransform()}
          transition={getTransition() as any}
          style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}
        >
          {showCurrent && isChess && (
            <motion.div
              initial={{ opacity: 1 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.15 }}
            >
              <ChessSVG />
            </motion.div>
          )}
          {showCurrent && !isChess && (
            <motion.div
              initial={{ opacity: 1 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.15 }}
            >
              <CarSVG />
            </motion.div>
          )}
          {showNext && !isChess && (
            <motion.div
              initial={{ opacity: 0, scale: 0.7 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: MORPH_RISE_DURATION * 0.6, delay: MORPH_RISE_DURATION * 0.2, ease: [0.34, 1.56, 0.64, 1] }}
            >
              <CarSVG />
            </motion.div>
          )}
          {showNext && isChess && (
            <motion.div
              initial={{ opacity: 0, scale: 0.7 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: MORPH_RISE_DURATION * 0.6, delay: MORPH_RISE_DURATION * 0.2, ease: [0.34, 1.56, 0.64, 1] }}
            >
              <ChessSVG />
            </motion.div>
          )}
        </motion.div>
      </div>

      <AnimatePresence>
        {showImpact && (
          <>
            <Shockwave />
            <GroundFlash />
            <BurstParticles />
          </>
        )}
      </AnimatePresence>

      <div
        style={{
          position: "absolute",
          bottom: "10%",
          left: "50%",
          transform: "translateX(-50%)",
          width: 180,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: 10,
        }}
      >
        <div
          style={{
            width: "100%",
            height: 3,
            borderRadius: 2,
            background: "rgba(255,255,255,0.08)",
            overflow: "hidden",
          }}
        >
          <motion.div
            style={{
              height: "100%",
              borderRadius: 2,
              background: "rgba(255,255,255,0.6)",
            }}
            initial={{ width: "0%" }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 0.3, ease: "easeOut" }}
          />
        </div>
        <span
          style={{
            fontFamily: "var(--font-mono, monospace)",
            fontSize: 11,
            color: "rgba(255,255,255,0.35)",
            letterSpacing: "0.15em",
          }}
        >
          {progress}%
        </span>
      </div>
    </div>
  )
}
